
"use client";

import { useState, useEffect } from 'react';
import Link from 'next/link';
import { SiteHeader } from "@/components/SiteHeader";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { useToast } from "@/hooks/use-toast";
import { PlusCircle, Trash2, Edit } from 'lucide-react';
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
  AlertDialogTrigger,
} from "@/components/ui/alert-dialog";
import { getVendors, type Vendor } from '@/ai/flows/vendor-flow';

export default function AdminPage() {
    const { toast } = useToast();
    const [vendors, setVendors] = useState<Vendor[]>([]);
    const [newVendorName, setNewVendorName] = useState('');
    const [newVendorDescription, setNewVendorDescription] = useState('');
    const [isLoading, setIsLoading] = useState(true);

    useEffect(() => {
      async function fetchVendors() {
        try {
          setIsLoading(true);
          const fetchedVendors = await getVendors();
          setVendors(fetchedVendors);
        } catch (error) {
          console.error("Failed to fetch vendors:", error);
          toast({
            variant: "destructive",
            title: "讀取店家失敗",
            description: "無法從 Google Sheet 讀取店家列表。",
          });
        } finally {
          setIsLoading(false);
        }
      }
      fetchVendors();
    }, [toast]);


    const handleAddVendor = (e: React.FormEvent) => {
        e.preventDefault();
        if (!newVendorName.trim()) {
            toast({
                variant: "destructive",
                title: "請輸入店家名稱",
            });
            return;
        }

        // This will be replaced with an API call to write to the sheet
        const newVendor = {
            id: `temp-${Date.now()}`,
            name: newVendorName,
            description: newVendorDescription,
            isActive: true,
        };

        // In a real app, this would be an API call and would refetch the data
        setVendors([...vendors, newVendor]);
        setNewVendorName('');
        setNewVendorDescription('');

        toast({
            title: "店家已新增 (模擬)",
            description: `${newVendorName} 已成功加入。請注意，此為模擬操作，尚未寫入 Google Sheet。`,
        });
    };

    const handleDeleteVendor = (vendorId: string, vendorName: string) => {
        // This will be replaced with an API call to update the sheet
        setVendors(vendors.filter(v => v.id !== vendorId));
        toast({
            title: "店家已刪除 (模擬)",
            description: `${vendorName} 已從列表中移除。請注意，此為模擬操作，尚未寫入 Google Sheet。`,
        });
    };

  return (
    <div className="min-h-screen bg-background font-body text-foreground">
      <SiteHeader />
      <main className="container mx-auto p-4 sm:p-6 lg:p-8">
        <h1 className="font-headline text-3xl font-bold mb-6">管理介面</h1>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
            {/* Add New Vendor */}
            <section>
                <Card>
                    <CardHeader>
                        <CardTitle className="flex items-center gap-2">
                            <PlusCircle className="h-6 w-6" />
                            <span>新增店家</span>
                        </CardTitle>
                        <CardDescription>在這裡建立新的便當店家。</CardDescription>
                    </CardHeader>
                    <CardContent>
                        <form onSubmit={handleAddVendor} className="space-y-4">
                            <Input
                                placeholder="店家名稱"
                                value={newVendorName}
                                onChange={(e) => setNewVendorName(e.target.value)}
                            />
                            <Input
                                placeholder="店家描述 (選填)"
                                value={newVendorDescription}
                                onChange={(e) => setNewVendorDescription(e.target.value)}
                            />
                            <Button type="submit" className="w-full">新增店家</Button>
                        </form>
                    </CardContent>
                </Card>
            </section>

            {/* Vendor List */}
            <section>
                <Card>
                    <CardHeader>
                        <CardTitle>店家列表</CardTitle>
                        <CardDescription>管理現有的店家及菜單。</CardDescription>
                    </CardHeader>
                    <CardContent className="space-y-4">
                        {isLoading ? (
                          <p>讀取中...</p>
                        ) : vendors.length > 0 ? (
                            vendors.map(vendor => (
                                <Card key={vendor.id} className="p-4 flex justify-between items-center">
                                    <div>
                                        <p className="font-semibold">{vendor.name}</p>
                                        <p className="text-sm text-muted-foreground">{vendor.description}</p>
                                    </div>
                                    <div className="flex items-center gap-2">
                                        <Link href={`/admin/menu/${vendor.id}?name=${encodeURIComponent(vendor.name)}`}>
                                          <Button variant="outline" size="sm" className="flex items-center gap-1">
                                            <Edit className="h-3 w-3" />
                                            編輯菜單
                                          </Button>
                                        </Link>
                                        <AlertDialog>
                                            <AlertDialogTrigger asChild>
                                                <Button variant="ghost" size="icon" aria-label={`刪除店家 ${vendor.name}`}>
                                                    <Trash2 className="h-4 w-4 text-destructive" />
                                                </Button>
                                            </AlertDialogTrigger>
                                            <AlertDialogContent>
                                                <AlertDialogHeader>
                                                    <AlertDialogTitle>確定要刪除店家嗎？</AlertDialogTitle>
                                                    <AlertDialogDescription>
                                                        此動作無法復原。這將會永久刪除店家「{vendor.name}」及其所有菜單資料。
                                                    </AlertDialogDescription>
                                                </AlertDialogHeader>
                                                <AlertDialogFooter>
                                                    <AlertDialogCancel>取消</AlertDialogCancel>
                                                    <AlertDialogAction onClick={() => handleDeleteVendor(vendor.id, vendor.name)}>確定刪除</AlertDialogAction>
                                                </AlertDialogFooter>
                                            </AlertDialogContent>
                                        </AlertDialog>
                                    </div>
                                </Card>
                            ))
                        ) : (
                          <p className="text-sm text-center text-muted-foreground py-4">您的 'vendors' 工作表中還沒有任何店家。</p>
                        )}
                    </CardContent>
                </Card>
            </section>
        </div>
      </main>
    </div>
  );
}
